package ui.admin;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import model.*;import util.*;import ui.common.TableStyle;
public class ManageEmployersPanel extends JPanel{ JTable table=new JTable(); public ManageEmployersPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Manage / Verify Companies"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);JPanel p=UITheme.panel();JButton v=UITheme.button("Verify");JButton u=UITheme.button("Unverify");p.add(v);p.add(u);add(p,BorderLayout.SOUTH);v.addActionListener(e->verify(true));u.addActionListener(e->verify(false));load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Company","City","Email","Verified"},0);for(Company c:new AdminController().companies())m.addRow(new Object[]{c.getId(),c.getCompanyName(),c.getCity(),c.getEmail(),c.isVerified()});table.setModel(m);TableStyle.apply(table);} void verify(boolean b){int r=table.getSelectedRow();if(r<0)return;new AdminController().verifyCompany(Integer.parseInt(table.getValueAt(r,0).toString()),b);load();}}
